import React, { useState, useEffect } from 'react';

const QuantumCircuitBuilder = () => {
  const [tailwindLoaded, setTailwindLoaded] = useState(false);
  const [circuit, setCircuit] = useState([]);
  const [autoExecute, setAutoExecute] = useState(true);
  const [sharedCircuit, setSharedCircuit] = useGlobalStorage('quantum-circuit', null);

  // Load Tailwind CSS
  useEffect(() => {
    if (!document.getElementById('tailwind-script')) {
      const tailwindScript = document.createElement('script');
      tailwindScript.id = 'tailwind-script';
      tailwindScript.src = 'https://cdn.tailwindcss.com';
      tailwindScript.onload = () => {
        setTimeout(() => setTailwindLoaded(true), 100);
      };
      document.head.appendChild(tailwindScript);
    } else {
      setTailwindLoaded(true);
    }
  }, []);

  // Set body background
  useEffect(() => {
    document.body.style.background = '#ffffff';
    document.documentElement.style.minHeight = '100%';
    return () => {
      document.body.style.background = '';
      document.documentElement.style.minHeight = '';
    };
  }, []);

  // Auto-execute circuit when it changes
  useEffect(() => {
    if (autoExecute && circuit.length > 0) {
      setSharedCircuit({ circuit, timestamp: Date.now() });
    }
  }, [circuit, autoExecute]);

  // Available quantum gates
  const gates = [
    { name: 'H', label: 'Hadamard', description: 'Creates superposition', color: '#10b981', emoji: '⚡' },
    { name: 'X', label: 'Pauli-X', description: 'Bit flip (NOT)', color: '#3b82f6', emoji: '↕️' },
    { name: 'Y', label: 'Pauli-Y', description: 'Y rotation', color: '#8b5cf6', emoji: '🔄' },
    { name: 'Z', label: 'Pauli-Z', description: 'Phase flip', color: '#ec4899', emoji: '⭮' },
    { name: 'S', label: 'Phase', description: '+90° phase shift', color: '#f59e0b', emoji: '↻' },
    { name: 'T', label: 'T Gate', description: '+45° phase shift', color: '#ef4444', emoji: '↺' }
  ];

  const addGate = (gateName) => {
    setCircuit(prev => [...prev, { id: Date.now(), gate: gateName }]);
  };

  const removeGate = (id) => {
    setCircuit(prev => prev.filter(g => g.id !== id));
  };

  const clearCircuit = () => {
    setCircuit([]);
    setSharedCircuit(null);
  };

  const executeCircuit = () => {
    setSharedCircuit({ circuit, timestamp: Date.now() });
  };

  const moveGate = (index, direction) => {
    const newCircuit = [...circuit];
    const newIndex = index + direction;
    if (newIndex >= 0 && newIndex < newCircuit.length) {
      [newCircuit[index], newCircuit[newIndex]] = [newCircuit[newIndex], newCircuit[index]];
      setCircuit(newCircuit);
    }
  };

  const getGateInfo = (gateName) => {
    return gates.find(g => g.name === gateName) || { color: '#666', emoji: '•' };
  };

  if (!tailwindLoaded) {
    return <div style={{ padding: '20px', textAlign: 'center', fontFamily: 'Inter, sans-serif' }}>Loading...</div>;
  }

  return (
    <div style={{ fontFamily: 'Inter, -apple-system, sans-serif' }} className="min-h-screen bg-white p-8">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-light text-gray-900 mb-2">Quantum Circuit Builder</h1>
          <p className="text-sm text-gray-500 font-light">Design quantum circuits and send them to the simulator</p>
        </div>

        {/* Gate Palette */}
        <div className="bg-white rounded-2xl p-8 mb-6" style={{ boxShadow: '0 20px 60px rgba(0,0,0,0.03)' }}>
          <h2 className="text-lg font-medium text-gray-900 mb-4">Gate Palette</h2>
          <p className="text-xs text-gray-500 mb-6 font-light">Click a gate to add it to your circuit</p>

          <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {gates.map(gate => (
              <button
                key={gate.name}
                onClick={() => addGate(gate.name)}
                className="px-6 py-4 rounded-xl text-white font-medium transition-all hover:scale-105 active:scale-95"
                style={{ 
                  backgroundColor: gate.color,
                  boxShadow: '0 4px 12px rgba(0,0,0,0.1)'
                }}
              >
                <div className="text-2xl mb-1">{gate.name}</div>
                <div className="text-xs font-light opacity-90">{gate.label}</div>
              </button>
            ))}
          </div>

          {/* Gate Descriptions */}
          <div className="mt-6 pt-6 border-t" style={{ borderColor: '#f0f0f0' }}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 text-xs text-gray-600">
              {gates.map(gate => (
                <div key={gate.name} className="flex items-start gap-2">
                  <span className="font-medium" style={{ color: gate.color }}>{gate.name}:</span>
                  <span className="font-light">{gate.description}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Circuit Display */}
        <div className="bg-white rounded-2xl p-8 mb-6" style={{ boxShadow: '0 20px 60px rgba(0,0,0,0.03)' }}>
          <div className="flex items-center justify-between mb-4">
            <div>
              <h2 className="text-lg font-medium text-gray-900">Circuit</h2>
              <p className="text-xs text-gray-500 font-light mt-1">
                {circuit.length} gate{circuit.length !== 1 ? 's' : ''} in sequence
              </p>
            </div>
            {circuit.length > 0 && (
              <button
                onClick={clearCircuit}
                className="px-4 py-2 text-sm text-gray-600 hover:text-gray-900 font-light"
              >
                Clear All
              </button>
            )}
          </div>

          {circuit.length === 0 ? (
            <div className="text-center py-12 text-gray-400 font-light">
              <div className="text-4xl mb-3">⚛️</div>
              <div className="text-sm">No gates added yet</div>
              <div className="text-xs mt-1">Click a gate above to start building</div>
            </div>
          ) : (
            <div className="space-y-3">
              {/* Circuit Visualization Line */}
              <div className="flex items-center gap-2 overflow-x-auto pb-4">
                <div className="text-xs text-gray-500 font-medium whitespace-nowrap mr-2">|ψ⟩ →</div>
                {circuit.map((item, index) => {
                  const gateInfo = getGateInfo(item.gate);
                  return (
                    <React.Fragment key={item.id}>
                      <div 
                        className="flex-shrink-0 w-16 h-16 rounded-lg flex items-center justify-center text-white font-bold text-xl"
                        style={{ 
                          backgroundColor: gateInfo.color,
                          boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                        }}
                      >
                        {item.gate}
                      </div>
                      {index < circuit.length - 1 && (
                        <div className="flex-shrink-0 w-8 h-0.5 bg-gray-200"></div>
                      )}
                    </React.Fragment>
                  );
                })}
                <div className="text-xs text-gray-500 font-medium whitespace-nowrap ml-2">→ |ψ'⟩</div>
              </div>

              {/* Gate List with Controls */}
              <div className="space-y-2">
                {circuit.map((item, index) => {
                  const gateInfo = getGateInfo(item.gate);
                  return (
                    <div
                      key={item.id}
                      className="flex items-center gap-3 p-4 rounded-xl bg-gray-50 border"
                      style={{ borderColor: '#f0f0f0' }}
                    >
                      <div className="flex items-center gap-3 flex-1">
                        <div className="text-xs text-gray-400 font-medium w-8">#{index + 1}</div>
                        <div 
                          className="w-10 h-10 rounded-lg flex items-center justify-center text-white font-bold"
                          style={{ backgroundColor: gateInfo.color }}
                        >
                          {item.gate}
                        </div>
                        <div className="flex-1">
                          <div className="text-sm font-medium text-gray-900">
                            {gates.find(g => g.name === item.gate)?.label}
                          </div>
                          <div className="text-xs text-gray-500 font-light">
                            {gates.find(g => g.name === item.gate)?.description}
                          </div>
                        </div>
                      </div>

                      {/* Controls */}
                      <div className="flex items-center gap-1">
                        <button
                          onClick={() => moveGate(index, -1)}
                          disabled={index === 0}
                          className="p-2 text-gray-400 hover:text-gray-600 disabled:opacity-30 disabled:cursor-not-allowed"
                          title="Move earlier"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                          </svg>
                        </button>
                        <button
                          onClick={() => moveGate(index, 1)}
                          disabled={index === circuit.length - 1}
                          className="p-2 text-gray-400 hover:text-gray-600 disabled:opacity-30 disabled:cursor-not-allowed"
                          title="Move later"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                          </svg>
                        </button>
                        <button
                          onClick={() => removeGate(item.id)}
                          className="p-2 text-red-400 hover:text-red-600 ml-2"
                          title="Remove gate"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                          </svg>
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="bg-white rounded-2xl p-8" style={{ boxShadow: '0 20px 60px rgba(0,0,0,0.03)' }}>
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-lg font-medium text-gray-900">Execution</h2>
              <p className="text-xs text-gray-500 font-light mt-1">Send circuit to quantum simulator</p>
            </div>

            <label className="flex items-center gap-3 cursor-pointer">
              <span className="text-sm text-gray-600 font-light">Auto-execute</span>
              <div className="relative">
                <input
                  type="checkbox"
                  checked={autoExecute}
                  onChange={(e) => setAutoExecute(e.target.checked)}
                  className="sr-only peer"
                />
                <div className="w-11 h-6 bg-gray-200 rounded-full peer peer-checked:bg-indigo-500 transition-colors"></div>
                <div className="absolute left-1 top-1 w-4 h-4 bg-white rounded-full transition-transform peer-checked:translate-x-5"></div>
              </div>
            </label>
          </div>

          {!autoExecute && circuit.length > 0 && (
            <button
              onClick={executeCircuit}
              className="w-full px-6 py-4 bg-indigo-500 text-white rounded-xl font-medium hover:bg-indigo-600 transition-colors"
              style={{ boxShadow: '0 4px 12px rgba(99, 102, 241, 0.2)' }}
            >
              Execute Circuit
            </button>
          )}

          {autoExecute && (
            <div className="text-center py-3 text-sm text-gray-500 font-light">
              Circuit automatically sends to simulator as you build
            </div>
          )}

          {/* Connection Status */}
          <div className="mt-6 pt-6 border-t" style={{ borderColor: '#f0f0f0' }}>
            <div className="flex items-center gap-2 text-xs text-gray-500">
              <div className="w-2 h-2 bg-green-400 rounded-full"></div>
              <span className="font-light">Broadcasting to quantum simulator</span>
            </div>
            <p className="text-xs text-gray-400 font-light mt-2">
              Circuits are automatically shared with all quantum simulator widgets on this canvas
            </p>
          </div>
        </div>

        {/* Famous Quantum Circuits */}
        <div className="mt-6 bg-white rounded-2xl p-8" style={{ boxShadow: '0 20px 60px rgba(0,0,0,0.03)' }}>
          <h2 className="text-lg font-medium text-gray-900 mb-4">Quick Start Circuits</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <button
              onClick={() => setCircuit([
                { id: Date.now(), gate: 'H' }
              ])}
              className="text-left px-4 py-3 rounded-xl border hover:bg-gray-50 transition-colors"
              style={{ borderColor: '#f0f0f0' }}
            >
              <div className="text-sm font-medium text-gray-900">Equal Superposition</div>
              <div className="text-xs text-gray-500 font-light mt-1">H → Creates 50/50 state</div>
            </button>

            <button
              onClick={() => setCircuit([
                { id: Date.now(), gate: 'X' }
              ])}
              className="text-left px-4 py-3 rounded-xl border hover:bg-gray-50 transition-colors"
              style={{ borderColor: '#f0f0f0' }}
            >
              <div className="text-sm font-medium text-gray-900">Bit Flip</div>
              <div className="text-xs text-gray-500 font-light mt-1">X → Flips |0⟩ to |1⟩</div>
            </button>

            <button
              onClick={() => setCircuit([
                { id: Date.now(), gate: 'H' },
                { id: Date.now() + 1, gate: 'T' },
                { id: Date.now() + 2, gate: 'H' }
              ])}
              className="text-left px-4 py-3 rounded-xl border hover:bg-gray-50 transition-colors"
              style={{ borderColor: '#f0f0f0' }}
            >
              <div className="text-sm font-medium text-gray-900">Phase Rotation</div>
              <div className="text-xs text-gray-500 font-light mt-1">H → T → H</div>
            </button>

            <button
              onClick={() => setCircuit([
                { id: Date.now(), gate: 'H' },
                { id: Date.now() + 1, gate: 'S' },
                { id: Date.now() + 2, gate: 'H' }
              ])}
              className="text-left px-4 py-3 rounded-xl border hover:bg-gray-50 transition-colors"
              style={{ borderColor: '#f0f0f0' }}
            >
              <div className="text-sm font-medium text-gray-900">S Gate Demo</div>
              <div className="text-xs text-gray-500 font-light mt-1">H → S → H</div>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuantumCircuitBuilder;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';

const CATEGORIES = {
  mentalHealth: {
    id: 'mentalHealth',
    name: 'Mental Health',
    color: '#6366f1',
    hoverColor: '#5558e3',
    lightColor: 'rgba(99, 102, 241, 0.1)',
    placeholder: "What's on your mind today?",
    fieldLabel: null,
    fieldPlaceholder: null,
    emptyMessage: 'No entries yet',
    emptySubtext: 'Start writing to create your first entry'
  },
  school: {
    id: 'school',
    name: 'School & Studies',
    color: '#0ea5e9',
    hoverColor: '#0284c7',
    lightColor: 'rgba(14, 165, 233, 0.1)',
    placeholder: 'What did you learn today?',
    fieldLabel: 'Subject or Topic',
    fieldPlaceholder: 'Subject or Topic (optional)',
    emptyMessage: 'No notes yet',
    emptySubtext: 'Start documenting your learning journey'
  },
  personal: {
    id: 'personal',
    name: 'Personal Favorites',
    color: '#f59e0b',
    hoverColor: '#d97706',
    lightColor: 'rgba(245, 158, 11, 0.1)',
    placeholder: 'What made you smile today?',
    fieldLabel: 'Title',
    fieldPlaceholder: 'Give it a title (optional)',
    emptyMessage: 'No memories yet',
    emptySubtext: 'Start capturing your favorite moments'
  }
};

function JournalNotebook() {
  const [tailwindLoaded, setTailwindLoaded] = useState(false);
  const [entries, setEntries] = useStorage('entries', []);
  const [activeCategory, setActiveCategory] = useState('mentalHealth');
  const [currentEntry, setCurrentEntry] = useState('');
  const [currentField, setCurrentField] = useState('');
  const [editingId, setEditingId] = useState(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    if (!document.getElementById('tailwind-script')) {
      const tailwindScript = document.createElement('script');
      tailwindScript.id = 'tailwind-script';
      tailwindScript.src = 'https://cdn.tailwindcss.com';
      tailwindScript.onload = () => {
        setTimeout(() => setTailwindLoaded(true), 100);
      };
      document.head.appendChild(tailwindScript);
    } else {
      setTailwindLoaded(true);
    }
  }, []);

  useEffect(() => {
    document.body.style.background = '#ffffff';
    document.documentElement.style.minHeight = '100%';
    return () => { 
      document.body.style.background = ''; 
      document.documentElement.style.minHeight = ''; 
    };
  }, []);

  const category = CATEGORIES[activeCategory];

  const filteredEntries = useMemo(() => {
    return entries.filter(e => e.category === activeCategory).sort((a, b) => b.createdAt - a.createdAt);
  }, [entries, activeCategory]);

  const handleSave = useCallback(() => {
    if (!currentEntry.trim()) return;

    if (editingId) {
      setEntries(prev => prev.map(entry => 
        entry.id === editingId 
          ? { ...entry, content: currentEntry, field: currentField, updatedAt: Date.now() }
          : entry
      ));
      setEditingId(null);
    } else {
      const newEntry = {
        id: Date.now().toString(),
        category: activeCategory,
        content: currentEntry,
        field: currentField,
        createdAt: Date.now(),
        updatedAt: Date.now()
      };
      setEntries(prev => [newEntry, ...prev]);
    }
    setCurrentEntry('');
    setCurrentField('');
    textareaRef.current?.focus();
  }, [currentEntry, currentField, editingId, activeCategory, setEntries]);

  const handleEdit = useCallback((entry) => {
    setCurrentEntry(entry.content);
    setCurrentField(entry.field || '');
    setEditingId(entry.id);
    textareaRef.current?.focus();
  }, []);

  const handleDelete = useCallback((id) => {
    setEntries(prev => prev.filter(entry => entry.id !== id));
    if (editingId === id) {
      setCurrentEntry('');
      setCurrentField('');
      setEditingId(null);
    }
  }, [editingId, setEntries]);

  const handleCancel = useCallback(() => {
    setCurrentEntry('');
    setCurrentField('');
    setEditingId(null);
  }, []);

  const handleCategoryChange = useCallback((categoryId) => {
    setActiveCategory(categoryId);
    setCurrentEntry('');
    setCurrentField('');
    setEditingId(null);
  }, []);

  const formatDate = useCallback((timestamp) => {
    const date = new Date(timestamp);
    const now = new Date();
    const isToday = date.toDateString() === now.toDateString();

    if (isToday) {
      return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
    }
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  }, []);

  if (!tailwindLoaded) {
    return <div style={{ padding: '20px', textAlign: 'center', fontFamily: 'Inter, -apple-system, sans-serif' }}>Loading...</div>;
  }

  return (
    <div style={{ fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, sans-serif', minHeight: '100vh' }}>
      {/* Header */}
      <div style={{ padding: '48px 48px 32px', borderBottom: '1px solid #f0f0f0' }}>
        <h1 style={{ fontSize: '32px', fontWeight: '300', color: '#1a1a1a', marginBottom: '8px', letterSpacing: '-0.02em' }}>
          Journal Notebook
        </h1>
        <p style={{ fontSize: '15px', color: '#666', fontWeight: '400' }}>
          Your personal space for mental health, learning, and favorite moments
        </p>
      </div>

      {/* Category Tabs */}
      <div style={{ padding: '32px 48px 0', borderBottom: '1px solid #f0f0f0' }}>
        <div style={{ display: 'flex', gap: '8px' }}>
          {Object.values(CATEGORIES).map(cat => (
            <button
              key={cat.id}
              onClick={() => handleCategoryChange(cat.id)}
              style={{
                padding: '14px 24px',
                fontSize: '15px',
                fontWeight: '500',
                border: 'none',
                borderBottom: activeCategory === cat.id ? `3px solid ${cat.color}` : '3px solid transparent',
                background: 'transparent',
                color: activeCategory === cat.id ? cat.color : '#666',
                cursor: 'pointer',
                transition: 'all 0.2s ease',
                marginBottom: '-1px'
              }}
              onMouseEnter={(e) => {
                if (activeCategory !== cat.id) {
                  e.target.style.color = '#333';
                }
              }}
              onMouseLeave={(e) => {
                if (activeCategory !== cat.id) {
                  e.target.style.color = '#666';
                }
              }}
            >
              {cat.name}
            </button>
          ))}
        </div>
      </div>

      {/* Entry Editor */}
      <div style={{ padding: '48px' }}>
        <div style={{ 
          background: '#ffffff', 
          borderRadius: '16px', 
          padding: '32px',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.04)',
          marginBottom: '48px',
          border: `1px solid ${category.lightColor}`
        }}>
          {category.fieldLabel && (
            <input
              type="text"
              value={currentField}
              onChange={(e) => setCurrentField(e.target.value)}
              placeholder={category.fieldPlaceholder}
              style={{
                width: '100%',
                padding: '16px 20px',
                fontSize: '16px',
                fontWeight: '500',
                border: '1px solid #f0f0f0',
                borderRadius: '12px',
                fontFamily: 'inherit',
                color: '#1a1a1a',
                background: '#fafafa',
                outline: 'none',
                transition: 'all 0.2s ease',
                marginBottom: '16px'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = category.color;
                e.target.style.background = '#ffffff';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = '#f0f0f0';
                e.target.style.background = '#fafafa';
              }}
            />
          )}
          <textarea
            ref={textareaRef}
            value={currentEntry}
            onChange={(e) => setCurrentEntry(e.target.value)}
            placeholder={category.placeholder}
            style={{
              width: '100%',
              minHeight: '180px',
              padding: '20px',
              fontSize: '16px',
              lineHeight: '1.6',
              border: '1px solid #f0f0f0',
              borderRadius: '12px',
              resize: 'vertical',
              fontFamily: 'inherit',
              color: '#1a1a1a',
              background: '#fafafa',
              outline: 'none',
              transition: 'all 0.2s ease'
            }}
            onFocus={(e) => {
              e.target.style.borderColor = category.color;
              e.target.style.background = '#ffffff';
            }}
            onBlur={(e) => {
              e.target.style.borderColor = '#f0f0f0';
              e.target.style.background = '#fafafa';
            }}
          />
          <div style={{ display: 'flex', gap: '12px', marginTop: '20px', justifyContent: 'flex-end' }}>
            {editingId && (
              <button
                onClick={handleCancel}
                style={{
                  padding: '14px 28px',
                  fontSize: '15px',
                  fontWeight: '500',
                  border: '1px solid #e0e0e0',
                  borderRadius: '10px',
                  background: '#ffffff',
                  color: '#666',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease'
                }}
                onMouseEnter={(e) => e.target.style.background = '#f5f5f5'}
                onMouseLeave={(e) => e.target.style.background = '#ffffff'}
              >
                Cancel
              </button>
            )}
            <button
              onClick={handleSave}
              disabled={!currentEntry.trim()}
              style={{
                padding: '14px 32px',
                fontSize: '15px',
                fontWeight: '500',
                border: 'none',
                borderRadius: '10px',
                background: currentEntry.trim() ? category.color : '#e0e0e0',
                color: '#ffffff',
                cursor: currentEntry.trim() ? 'pointer' : 'not-allowed',
                transition: 'all 0.2s ease',
                boxShadow: currentEntry.trim() ? `0 4px 16px ${category.lightColor}` : 'none'
              }}
              onMouseEnter={(e) => {
                if (currentEntry.trim()) e.target.style.background = category.hoverColor;
              }}
              onMouseLeave={(e) => {
                if (currentEntry.trim()) e.target.style.background = category.color;
              }}
            >
              {editingId ? 'Update Entry' : 'Save Entry'}
