            }}>
              {/* Elbow Method Chart */}
              <div style={{
                display: 'flex',
                flexDirection: 'column',
                height: '400px',
                padding: '25px 20px',
                borderBottom: '1px solid #e0e0e0'
              }}>
                <h3 style={{
                  fontSize: '16px',
                  fontWeight: 500,
                  color: '#222',
                  marginBottom: '1em',
                  margin: '0 0 1em 0'
                }}>
                  Elbow Method
                </h3>
                <div style={{
                  flex: 1,
                  position: 'relative',
                  minHeight: '300px'
                }}>
                  {isCalculatingElbow ? (
                    <div style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      height: '300px',
                      color: '#72777d',
                      fontSize: '0.875em'
                    }}>
                      Calculating...
                    </div>
                  ) : elbowData.length > 0 ? (
                    <ElbowChart elbowData={elbowData} />
                  ) : (
                    <div style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      height: '300px',
                      color: '#72777d',
                      fontSize: '0.875em'
                    }}>
                      Add points to see elbow method
                    </div>
                  )}
                </div>
              </div>

              {/* Inertia Over Time Chart */}
              <div style={{
                display: 'flex',
                flexDirection: 'column',
                height: '400px',
                padding: '25px 20px',
                borderBottom: 'none'
              }}>
                <h3 style={{
                  fontSize: '16px',
                  fontWeight: 500,
                  color: '#222',
                  marginBottom: '1em',
                  margin: '0 0 1em 0'
                }}>
                  Inertia Over Time
                </h3>
                <div style={{
                  flex: 1,
                  position: 'relative',
                  minHeight: '300px'
                }}>
                  {inertiaHistory.length > 0 ? (
                    <InertiaChart inertiaHistory={inertiaHistory} />
                  ) : (
                    <div style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      height: '300px',
                      color: '#72777d',
                      fontSize: '0.875em'
                    }}>
                      Run iterations to see convergence
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default MLVisualization;

